+  // --------------------------------------------------------------------------
+  // Event System
+  // --------------------------------------------------------------------------
+
+  addEventListener(listener: EmbeddingEventListener): void {
+    this.embeddingListeners.add(listener);
+  }
+
+  removeEventListener(listener: EmbeddingEventListener): void {
+    this.embeddingListeners.delete(listener);
+  }
